1	-- -------------------------------------------------------------------------------------------------
2	-- Copyright (c) Lukas Vik. All rights reserved.
3	--
4	-- This file is part of the hdl-modules project, a collection of reusable, high-quality,
5	-- peer-reviewed VHDL building blocks.
6	-- https://hdl-modules.com
7	-- https://github.com/hdl-modules/hdl-modules
8	-- -------------------------------------------------------------------------------------------------
9	
10	library ieee;
11	use ieee.std_logic_1164.all;
12	use ieee.numeric_std.all;
13	
14	library osvvm;
15	use osvvm.RandomPkg.RandomPType;
16	
17	library vunit_lib;
18	use vunit_lib.check_pkg.all;
19	use vunit_lib.integer_array_pkg.all;
20	use vunit_lib.queue_pkg.all;
21	use vunit_lib.random_pkg.all;
22	use vunit_lib.run_pkg.all;
23	
24	library bfm;
25	use bfm.stall_bfm_pkg.stall_configuration_t;
26	
27	library common;
28	use common.types_pkg.all;
29	
30	
31	entity tb_fifo is
32	  generic (
33	    depth : positive;
34	    almost_full_level : natural := 0;
35	    almost_empty_level : natural := 0;
36	    read_stall_probability_percent : natural := 20;
37	    write_stall_probability_percent : natural := 20;
38	    enable_last : boolean := false;
39	    enable_packet_mode : boolean := false;
40	    enable_drop_packet : boolean := false;
41	    enable_peek_mode : boolean := false;
42	    enable_output_register : boolean := false;
43	    runner_cfg : string
44	  );
45	end entity;
46	
47	architecture tb of tb_fifo is
48	
49	  -- Generic constants
50	  constant width : positive := 8;
51	
52	  -- DUT ports
53	  signal clk : std_ulogic := '0';
54	  signal level : natural range 0 to depth := 0;
55	
56	  signal write_ready, write_valid, write_last, almost_full : std_ulogic := '0';
57	  signal read_ready, read_valid, read_last, read_peek_mode, almost_empty : std_ulogic := '0';
58	  signal write_data, read_data : std_ulogic_vector(width - 1 downto 0) := (others => '0');
59	
60	  signal drop_packet : std_ulogic := '0';
61	
62	  -- Testbench stuff
63	  constant read_stall_config : stall_configuration_t := (
64	    stall_probability => real(read_stall_probability_percent) / 100.0,
65	    min_stall_cycles => 1,
66	    max_stall_cycles => 3
67	  );
68	  constant write_stall_config : stall_configuration_t := (
69	    stall_probability => real(write_stall_probability_percent) / 100.0,
70	    min_stall_cycles => 1,
71	    max_stall_cycles => 3
72	  );
73	
74	  constant write_queue, read_queue : queue_t := new_queue;
75	
76	  signal num_beats_written, num_packets_written, num_packets_read : natural := 0;
77	  signal has_gone_full_times, has_gone_empty_times : integer := 0;
78	
79	  signal enable_read : std_ulogic := '1';
80	
81	begin
82	
83	  test_runner_watchdog(runner, 1 ms);
84	  clk <= not clk after 2 ns;
85	
86	
87	  ------------------------------------------------------------------------------
88	  main : process
89	
90	    variable rnd : RandomPType;
91	
92	    variable expected_num_packets_written, expected_num_packets_read : natural := 0;
93	
94	    procedure run_test(
95	      num_beats : natural;
96	      push_packet_to_checker_times : natural := 1
97	    ) is
98	      constant num_bytes : natural := num_beats * width / 8;
99	      variable data, data_copy : integer_array_t := null_integer_array;
100	    begin
101	      if num_beats > 0 then
102	        random_integer_array(
103	          rnd => rnd,
104	          integer_array => data,
105	          width => num_bytes,
106	          bits_per_word => 8,
107	          is_signed => false
108	        );
109	
110	        for packet_check_idx in 0 to push_packet_to_checker_times - 1 loop
111	          data_copy := copy(data);
112	          push_ref(read_queue, data_copy);
113	
114	          expected_num_packets_read := expected_num_packets_read + 1;
115	        end loop;
116	
117	        push_ref(write_queue, data);
118	
119	        expected_num_packets_written := expected_num_packets_written + 1;
120	      end if;
121	    end procedure;
122	
123	    procedure wait_until_write_done is
124	    begin
125	      wait until num_packets_written = expected_num_packets_written and rising_edge(clk);
126	    end procedure;
127	
128	    procedure wait_until_done is
129	    begin
130	      wait until num_packets_written = expected_num_packets_written
131	        and num_packets_read = expected_num_packets_read
132	        and rising_edge(clk);
133	    end procedure;
134	
135	    procedure pulse_drop_packet is
136	    begin
137	      drop_packet <= '1';
138	      wait until rising_edge(clk);
139	      drop_packet <= '0';
140	    end procedure;
141	
142	  begin
143	    test_runner_setup(runner, runner_cfg);
144	    rnd.InitSeed(get_string_seed(runner_cfg));
145	
146	    if run("test_init_state") then
147	      check_equal(read_valid, '0');
148	      check_equal(write_ready, '1');
149	      check_equal(almost_full, '0');
150	      check_equal(almost_empty, '1');
151	
152	      wait until
153	        read_valid'event or write_ready'event or almost_full'event or almost_empty'event
154	        for 1 us;
155	
156	      check_equal(read_valid, '0');
157	      check_equal(write_ready, '1');
158	      check_equal(almost_full, '0');
159	      check_equal(almost_empty, '1');
160	
161	    elsif run("test_write_faster_than_read") then
162	      for packet_idx in 0 to 1000 loop
163	        run_test(num_beats=>rnd.Uniform(1, 5));
164	      end loop;
165	
166	      wait_until_done;
167	      check_relation(has_gone_full_times > 500, "Got " & to_string(has_gone_full_times));
168	
169	    elsif run("test_read_faster_than_write") then
170	      for packet_idx in 0 to 1000 loop
171	        run_test(num_beats=>rnd.Uniform(1, 5));
172	      end loop;
173	
174	      wait_until_done;
175	      check_relation(has_gone_empty_times > 500, "Got " & to_string(has_gone_empty_times));
176	
177	    elsif run("test_packet_mode_random_data") then
178	      for packet_idx in 0 to 1000 loop
179	        run_test(num_beats=>rnd.Uniform(1, 5));
180	      end loop;
181	
182	    elsif run("test_packet_mode_status") then
183	      -- Start writing a packet and check status is the middle
184	      enable_read <= '0';
185	      run_test(num_beats=>depth - 1);
186	
187	      wait until num_beats_written = depth - 2 and rising_edge(clk);
188	      check_relation(level > 0);
189	      check_equal(read_valid, False);
190	
191	      -- Allow the test to finish
192	      enable_read <= '1';
193	
194	    elsif run("test_packet_mode_deep") then
195	      -- Show that the FIFO can be filled with lasts
196	
197	      -- Fill the FIFO with lasts
198	      enable_read <= '0';
199	
200	      for beat_idx in 1 to depth loop
201	        run_test(num_beats=>1);
202	      end loop;
203	      wait_until_write_done;
204	
205	      enable_read <= '1';
206	      wait until read_ready and read_valid and rising_edge(clk);
207	      enable_read <= '0';
208	
209	      run_test(num_beats=>1);
210	      wait_until_write_done;
211	
212	      enable_read <= '1';
213	      wait_until_done;
214	
215	      -- Fill the FIFO with lasts again
216	      enable_read <= '0';
217	      for i in 1 to depth loop
218	        run_test(num_beats=>1);
219	      end loop;
220	      wait_until_write_done;
221	
222	      enable_read <= '1';
223	      wait_until_done;
224	
225	      wait until rising_edge(clk);
226	      check_equal(read_valid, '0');
227	
228	    elsif run("test_drop_packet_random_data") then
229	      -- Write and read some data, to make the pointers advance a little.
230	      run_test(num_beats=>depth * 3 / 4);
231	      -- Write another packet, which we will drop so it is not pushed to checker.
232	      -- Note that the length chosen will make the write pointer wraparound.
233	      run_test(num_beats=>depth / 2, push_packet_to_checker_times=>0);
234	
235	      -- Wait until the first packet is fully written
236	      wait until write_ready and write_valid and write_last and rising_edge(clk);
237	      wait until rising_edge(clk);
238	      -- Set drop_packet on the very last beat of the second packet.
239	      -- The whole second packet should be dropped.
240	      wait until write_ready and write_valid and write_last;
241	      pulse_drop_packet;
242	
243	      -- Write and verify a clean packet. Should be the only thing remaining in the FIFO.
244	      wait_until_done;
245	      enable_read <= '0';
246	      run_test(num_beats=>4);
247	      wait_until_write_done;
248	      check_equal(level, 4);
249	
250	      enable_read <= '1';
251	      wait_until_done;
252	      check_equal(read_valid, '0');
253	      check_equal(level, 0);
254	
255	    elsif run("test_almost_full") then
256	      check_equal(almost_full, '0');
257	
258	      enable_read <= '0';
259	      run_test(num_beats=>almost_full_level - 1);
260	      wait_until_write_done;
261	      check_equal(almost_full, '0');
262	
263	      run_test(num_beats=>1);
264	      wait_until_write_done;
265	      check_equal(almost_full, '1');
266	
267	      enable_read <= '1';
268	      wait until read_ready and read_valid and rising_edge(clk);
269	      wait until rising_edge(clk);
270	
271	      if almost_full_level = depth then
272	        -- One cycle more latency in this configuration.
273	        check_equal(almost_full, '1');
274	        -- Make sure that another pop does not occur;
275	        enable_read <= '0';
276	        wait until rising_edge(clk);
277	      end if;
278	      -- Should have fallen after the read
279	      check_equal(almost_full, '0');
280	
281	      -- Allow the test to finish
282	      enable_read <= '1';
283	
284	    elsif run("test_almost_empty") then
285	      check_equal(almost_empty, '1');
286	
287	      enable_read <= '0';
288	      run_test(num_beats=>almost_empty_level);
289	      wait_until_write_done;
290	      check_equal(almost_empty, '1');
291	
292	      run_test(num_beats=>1);
293	      wait_until_write_done;
294	      if almost_empty_level = 0 then
295	        -- One cycle more latency in this configuration
296	        check_equal(almost_empty, '1');
297	        wait until rising_edge(clk);
298	
299	        if enable_output_register then
300	          -- One cycle more latency in this configuration
301	          check_equal(almost_empty, '1');
302	          wait until rising_edge(clk);
303	        end if;
304	      end if;
305	      check_equal(almost_empty, '0');
306	
307	      enable_read <= '1';
308	      wait until read_ready and read_valid and rising_edge(clk);
309	      wait until rising_edge(clk);
310	      check_equal(almost_empty, '1');
311	
312	    elsif run("test_peek_mode") then
313	      for packet_idx in 0 to 10 loop
314	        -- Push four copies of the packet to checker, since we will peek read three below
315	        run_test(num_beats=>depth / 4 + packet_idx, push_packet_to_checker_times=>4);
316	      end loop;
317	
318	      for packet_idx in 0 to 10 loop
319	        -- Peek read packet three times
320	        read_peek_mode <= '1';
321	        for peek_idx in 0 to 2 loop
322	          wait until read_ready and read_valid and read_last and rising_edge(clk);
323	        end loop;
324	
325	        -- Read out packet for real
326	        read_peek_mode <= '0';
327	        wait until read_ready and read_valid and read_last and rising_edge(clk);
328	      end loop;
329	
330	    end if;
331	
332	    wait_until_done;
333	
334	    test_runner_cleanup(runner);
335	  end process;
336	
337	
338	  ------------------------------------------------------------------------------
339	  axi_stream_master_inst : entity bfm.axi_stream_master
340	    generic map (
341	      data_width => write_data'length,
342	      data_queue => write_queue,
343	      stall_config => write_stall_config,
344	      logger_name_suffix => " - write"
345	    )
346	    port map (
347	      clk => clk,
348	      --
