387	
388	    -- If there was a read transaction last clock cycle, and we now want to read but there is no
389	    -- data available.
390	    if read_transaction and read_ready and not read_valid then
391	      has_gone_empty_times <= has_gone_empty_times + 1;
392	    end if;
393	
394	    -- If there was a write transaction last clock cycle, and we now want to write but the fifo
395	    -- is full.
396	    if write_transaction and write_valid and not write_ready then
397	      has_gone_full_times <= has_gone_full_times + 1;
398	    end if;
399	
400	    read_transaction := read_ready and read_valid;
401	    write_transaction := write_ready and write_valid;
402	  end process;
403	
404	
405	  ------------------------------------------------------------------------------
406	  check_no_bubble_cycles_in_packet_mode : if (
407	    enable_packet_mode or enable_drop_packet or enable_peek_mode
408	  ) generate
409	    signal start_event, end_event, en : std_ulogic := '0';
410	  begin
