414	    end_event <= (read_ready and read_valid and read_last);
415	    en <= '1';
416	
417	    check_stable(
418	      clock=>clk,
419	      en=>en,
420	      -- Start check when valid arrives
421	      start_event=>read_valid,
422	      -- End check when last arrives
423	      end_event=>end_event,
424	      -- Assert that valid is always asserted until last arrives
425	      expr=>read_valid,
